pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title VelocityPresale
 * @dev Pre-sale contract for VELO token with vesting mechanism
 */
contract VelocityPresale is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // Token being sold
    IERC20 public immutable token;

    // Payment token (ETH or USDT)
    address public immutable paymentToken;

    // Presale parameters
    uint256 public immutable presalePrice; // Tokens per payment unit
    uint256 public immutable startTime;
    uint256 public immutable endTime;
    uint256 public immutable hardCap;
    uint256 public immutable softCap;
    uint256 public immutable minPurchase;
    uint256 public immutable maxPurchase;

    // State variables
    uint256 public tokensSold;
    uint256 public totalRaised;
    bool public presaleEnded;
    bool public presaleClaimable;

    // User purchases
    struct Purchase {
        uint256 paymentAmount;
        uint256 tokenAmount;
        uint256 timestamp;
        bool claimed;
    }

    mapping(address => Purchase) public purchases;
    address[] public purchasers;

    // Whitelist
    mapping(address => bool) public isWhitelisted;
    bool public whitelistRequired;

    // Events
    event TokensPurchased(address indexed purchaser, uint256 paymentAmount, uint256 tokenAmount);
    event PresaleEnded(uint256 totalRaised, uint256 tokensSold);
    event TokensClaimed(address indexed purchaser, uint256 tokenAmount);
    event WhitelistUpdated(address indexed account, bool status);
    event PresaleClaimableEnabled();
    event FundsWithdrawn(address indexed recipient, uint256 amount);

    /**
     * @dev Constructor to initialize the presale
     * @param _token Address of the VELO token
     * @param _paymentToken Address of payment token (address(0) for ETH)
     * @param _presalePrice Price in tokens per payment unit
     * @param _startTime Start time of presale
     * @param _endTime End time of presale
     * @param _hardCap Maximum amount to raise
     * @param _softCap Minimum amount to raise
     * @param _minPurchase Minimum purchase amount
     * @param _maxPurchase Maximum purchase amount per wallet
     */
    constructor(
        address _token,
        address _paymentToken,
        uint256 _presalePrice,
        uint256 _startTime,
        uint256 _endTime,
        uint256 _hardCap,
        uint256 _softCap,
        uint256 _minPurchase,
        uint256 _maxPurchase
    ) Ownable(msg.sender) {
        require(_token != address(0), "Invalid token address");
        require(_startTime >= block.timestamp, "Start time in the past");
        require(_endTime > _startTime, "End time before start time");
        require(_hardCap > _softCap, "Hard cap must be greater than soft cap");
        require(_minPurchase > 0, "Min purchase must be greater than 0");
        require(_maxPurchase > _minPurchase, "Max purchase must be greater than min purchase");

        token = IERC20(_token);
        paymentToken = _paymentToken;
        presalePrice = _presalePrice;
        startTime = _startTime;
        endTime = _endTime;
        hardCap = _hardCap;
        softCap = _softCap;
        minPurchase = _minPurchase;
        maxPurchase = _maxPurchase;
        whitelistRequired = true; // Default to whitelist required
    }

    /**
     * @dev Buy tokens with ETH
     */
    function buyTokens() external payable nonReentrant {
        require(paymentToken == address(0), "Use buyTokensWithToken() for token payments");
        _purchase(msg.value, msg.sender);
    }

    /**
     * @dev Buy tokens with ERC20 token
     * @param _amount Amount of payment tokens to spend
     */
    function buyTokensWithToken(uint256 _amount) external nonReentrant {
        require(paymentToken != address(0), "Use buyTokens() for ETH payments");

        IERC20(paymentToken).safeTransferFrom(msg.sender, address(this), _amount);
        _purchase(_amount, msg.sender);
    }

    /**
     * @dev Internal purchase logic
     * @param _paymentAmount Amount of payment
     * @param _purchaser Address of the purchaser
     */
    function _purchase(uint256 _paymentAmount, address _purchaser) internal {
        require(block.timestamp >= startTime, "Presale not started");
        require(block.timestamp <= endTime, "Presale ended");
        require(!presaleEnded, "Presale manually ended");
        require(_paymentAmount >= minPurchase, "Below minimum purchase");
        require(_paymentAmount <= maxPurchase, "Above maximum purchase");

        if (whitelistRequired) {
            require(isWhitelisted[_purchaser], "Not whitelisted");
        }

        // Calculate token amount
        uint256 tokenAmount = _paymentAmount * presalePrice;

        // Check hard cap
        require(totalRaised + _paymentAmount <= hardCap, "Hard cap reached");

        // Update state
        tokensSold += tokenAmount;
        totalRaised += _paymentAmount;

        // Record purchase
        Purchase storage purchase = purchases[_purchaser];
        purchase.paymentAmount += _paymentAmount;
        purchase.tokenAmount += tokenAmount;
        purchase.timestamp = block.timestamp;

        // Add to purchasers list if new
        if (purchase.tokenAmount == tokenAmount) {
            purchasers.push(_purchaser);
        }

        emit TokensPurchased(_purchaser, _paymentAmount, tokenAmount);
    }

    /**
     * @dev Claim purchased tokens after presale ends
     */
    function claimTokens() external nonReentrant {
        require(presaleClaimable, "Tokens not claimable yet");

        Purchase storage purchase = purchases[msg.sender];
        require(purchase.tokenAmount > 0, "No tokens to claim");
        require(!purchase.claimed, "Already claimed");

        purchase.claimed = true;
        token.safeTransfer(msg.sender, purchase.tokenAmount);

        emit TokensClaimed(msg.sender, purchase.tokenAmount);
    }

    /**
     * @dev Owner: End presale manually
     */
    function endPresale() external onlyOwner {
        require(block.timestamp >= startTime, "Presale not started");
        require(!presaleEnded, "Already ended");

        presaleEnded = true;

        emit PresaleEnded(totalRaised, tokensSold);
    }

    /**
     * @dev Owner: Enable token claiming
     */
    function enableClaiming() external onlyOwner {
        presaleClaimable = true;

        emit PresaleClaimableEnabled();
    }

    /**
     * @dev Owner: Add user to whitelist
     */
    function addToWhitelist(address _account) external onlyOwner {
        isWhitelisted[_account] = true;

        emit WhitelistUpdated(_account, true);
    }

    /**
     * @dev Owner: Remove user from whitelist
     */
    function removeFromWhitelist(address _account) external onlyOwner {
        isWhitelisted[_account] = false;

        emit WhitelistUpdated(_account, false);
    }

    /**
     * @dev Owner: Add multiple users to whitelist
     */
    function addMultipleToWhitelist(address[] calldata _accounts) external onlyOwner {
        for (uint256 i = 0; i < _accounts.length; i++) {
            isWhitelisted[_accounts[i]] = true;
            emit WhitelistUpdated(_accounts[i], true);
        }
    }

    /**
     * @dev Owner: Set whitelist requirement
     */
    function setWhitelistRequired(bool _required) external onlyOwner {
        whitelistRequired = _required;
    }

    /**
     * @dev Owner: Withdraw raised funds
     * @param _recipient Address to send funds to
     */
    function withdrawFunds(address _recipient) external onlyOwner {
        require(_recipient != address(0), "Invalid recipient");

        if (paymentToken == address(0)) {
            uint256 balance = address(this).balance;
            require(balance > 0, "No ETH to withdraw");
            (bool success, ) = payable(_recipient).call{value: balance}("");
            require(success, "ETH withdrawal failed");

            emit FundsWithdrawn(_recipient, balance);
        } else {
            uint256 balance = IERC20(paymentToken).balanceOf(address(this));
            require(balance > 0, "No tokens to withdraw");
            IERC20(paymentToken).safeTransfer(_recipient, balance);

            emit FundsWithdrawn(_recipient, balance);
        }
    }

    /**
     * @dev Owner: Withdraw unsold tokens
     * @param _recipient Address to send tokens to
     */
    function withdrawUnsoldTokens(address _recipient) external onlyOwner {
        require(_recipient != address(0), "Invalid recipient");

        uint256 balance = token.balanceOf(address(this));
        require(balance > 0, "No tokens to withdraw");

        token.safeTransfer(_recipient, balance);
    }

    /**
     * @dev Get presale status
     */
    function getPresaleStatus() external view returns (
        uint256 _tokensSold,
        uint256 _totalRaised,
        uint256 _hardCap,
        uint256 _softCap,
        uint256 _startTime,
        uint256 _endTime,
        bool _isActive,
        bool _ended,
        bool _claimable,
        uint256 _purchaserCount
    ) {
        return (
            tokensSold,
            totalRaised,
            hardCap,
            softCap,
            startTime,
            endTime,
            block.timestamp >= startTime && block.timestamp <= endTime && !presaleEnded,
            presaleEnded,
            presaleClaimable,
            purchasers.length
        );
    }

    /**
     * @dev Get user purchase info
     * @param _user Address of the user
     */
    function getUserPurchase(address _user) external view returns (
        uint256 paymentAmount,
        uint256 tokenAmount,
        uint256 timestamp,
        bool claimed
    ) {
        Purchase memory purchase = purchases[_user];
        return (
            purchase.paymentAmount,
            purchase.tokenAmount,
            purchase.timestamp,
            purchase.claimed
        );
    }

    /**
     * @dev Get all purchasers
     */
    function getPurchasers() external view returns (address[] memory) {
        return purchasers;
    }

    /**
     * @dev Receive ETH
     */
    receive() external payable {
        _purchase(msg.value, msg.sender);
    }
}

